mapper.select:
SELECT COALESCE(MAX(floor_no), 0) + 1
FROM help_answers
WHERE help_id = #{helpId}

mapper.update:
UPDATE help_answers
SET like_count = GREATEST(0, like_count + #{delta})
WHERE answer_id = #{answerId}

mapper.select:
SELECT COUNT(*)
FROM help_answer_likes
WHERE answer_id = #{answerId}
  AND user_id = #{userId}

mapper.delete:
DELETE FROM help_answer_likes
WHERE answer_id = #{answerId}
  AND user_id = #{userId}
